tests.test_body:
; Function Attrs: noinline memory(none)
declare i32 @demo3() #0

define void @foo3() {
  %call = call i32 @demo3()
  ret void
}

attributes #0 = { noinline memory(none) }

; Function Attrs: noinline memory(none)
define hidden ptr @demo2() #0 {
  ret ptr null
}

attributes #0 = { noinline memory(none) }

; Function Attrs: noinline memory(none)
declare hidden ptr @demo2() #0

define ptr @foo2() {
  %call = call ptr @demo2()
  ret ptr %call
}

attributes #0 = { noinline memory(none) }

; Function Attrs: noinline memory(none)
declare ptr @demo1(ptr returned) #0

define ptr @foo1(ptr %arg) {
  %call = call ptr @demo1(ptr %arg)
  ret ptr %call
}

attributes #0 = { noinline memory(none) }

target datalayout = "e-m:e-i64:64-f80:128-n8:16:32:64-S128"
target triple = "x86_64-unknown-linux-gnu"

; Function Attrs: noinline nounwind memory(read)
define i32 @compute(ptr noundef nonnull %ptr, i32 %x) #0 {
  ret i32 %x
}

attributes #0 = { noinline nounwind memory(read) }
